  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('4211ec3e-e6c4-4fb0-b086-6b00c32650f4', 'slidesai', 'SlidesAI', 'SlidesAI is an AI-powered slide generation tool focused on quickly converting text content into structured presentations. It operates as a plugin withinGoogle SlidesandMicrosoft PowerPoint, aiming to help users rapidly create draft slides within familiar office software, rather than replacing design tools.The core value of SlidesAI lies insaving time when starting presentations from a blank page, making it particularly suitable for teaching, reporting, or explanatory presentation scenarios.', '', 'https://www.slidesai.io/?utm_source=freeai.run', 'https://www.slidesai.io/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
