  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('30594f83-ab90-4b4e-bd18-ecd567cf25d6', 'shotai', 'ShotAI', 'ShotAI is a browser-based AI image and video generation platform designed to quickly create visual content from text prompts or images. Users can generate images, create short videos, and perform basic image editing within a single platform without switching between multiple AI tools. Unlike some tools that only provide a single generation model, this type of platform focuses more on integrating multiple AI models and creative tools, allowing users to experiment with different styles within the same workflow. ShotAI is better suited for social media content creation, advertising asset generation, and creative concept visuals rather than complex video editing or professional film post-production.', '', 'https://shotai.app/?utm_source=freeai.run', 'https://shotai.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
