  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('98a78f62-b015-477d-b584-df9d2e77a6a0', 'runway-gen-5', 'runway gen 5', 'runwaygen5.org presents Runway Gen-5 as an AI short-video tool you can use directly in the browser: you describe shots with prompts, optionally upload reference images for image-to-video, and adjust aspect ratio, quality tier, and per-clip duration on the page. The site also lists multiple model names and add-on capability labels; whether all of them unlock on a given plan and how that maps to Runway’s official product line can only be verified against your account limits, checkout, and the brand’s public information after sign-in. The sections below summarize what this domain’s pages show and typical decision points, without repeating countdown-style promo copy.', '', 'https://www.runwaygen5.org/?utm_source=freeai.run', 'https://www.runwaygen5.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
