  VALUES ('bb26f111-c5a8-4802-9875-ce4dfd9b65f0', 'seedance-30-1088', 'seedance 3.0', 'Seedance‑3 is an AI-powered platform for generating videos from text and images. Users can quickly create short clips and multi-scene videos using text prompts or static images. It primarily addresses the challenge of producing dynamic videos for non-professional users without shooting equipment or editing experience. Compared to similar tools, Seedance‑3 emphasizes multi-scene storytelling, audio synchronization, and high-resolution output, making it suitable for social media content creation, educational presentations, and concept videos, but not ideal for feature films, complex movies, or strict commercial advertising projects.', '', 'https://www.seedance-3.org/?utm_source=freeai.run', 'https://www.seedance-3.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
