  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('9271b882-91eb-4078-ac55-749717fcd081', 'seeddance', 'Seeddance', 'SeedDance is an AI-powered video generation platform that allows users to create short video content by entering text prompts or uploading images. The platform is primarily used for quickly producing visual assets such as social media videos, creative concept demos, or simple animated clips. Compared with traditional video production software, it does not rely on complex timeline editing. Instead, a generative model automatically handles the creation of visuals, motion, and style. Unlike some video tools that only provide a single model, platforms like this usually integrate multiple generation capabilities, enabling users to create video, image, or audio assets within the same interface. This makes it especially suitable for content prototyping and short-form video concept testing.', '', 'https://seeddance.app/?utm_source=freeai.run', 'https://seeddance.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
