  VALUES ('074265c7-8bba-44e4-ad9a-8c3d9a3d7544', 'biovelt', 'Biovelt', 'Biovelt 是一款“Link‑in‑Bio”工具，用于将社交媒体个人简介中的单一链接扩展为一个集中展示页面。它帮助创作者、自由职业者和小型企业将网站、作品集、社交账号及最新活动汇总在同一个链接中，让粉丝可以快速访问。与传统社交简介链接不同，Biovelt 提供页面自定义、基础访问统计以及链接管理功能，非常适合希望简化在线展示且无需搭建完整网站的用户。', '', 'https://biovelt.com/?utm_source=freeai.run', 'https://biovelt.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
