  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('47499d25-c357-4dce-bdb1-fbd58b31c5e5', 'image-to-prompt', 'Image to Prompt', 'imagetoprompt.appis an online image-to-AI-prompt tool that automatically generates detailed prompts from uploaded images for use in AI image generators. It extracts the subject, style, and scene elements from images and integrates color, lighting, and composition information into structured text, ready for direct use in platforms like Midjourney, Stable Diffusion, and DALL‑E. Unlike traditional image recognition or tag-generation tools, its primary goal is to support creative workflows and prompt engineering, allowing users to quickly obtain actionable prompts without manual brainstorming. The interface is clean, requires no registration, and is ideal for collecting creative inspiration, generating prompts, or learning prompt engineering in reverse.', '', 'https://imagetoprompt.app/?utm_source=freeai.run', 'https://imagetoprompt.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
