  VALUES ('8d5a9c12-662f-43e9-af9d-3bbbc34e6f26', 'aback-launch', 'Aback Launch', 'Aback Launch is a platform focused on showcasing and promoting early-stage projects, targeting entrepreneurs, product managers, and developers. It provides independent showcase pages for projects to enhance search engine visibility and long-term exposure. Unlike standard product directories, Aback Launch emphasizes content review and structured pages, offering sustainable discovery channels for early or growing projects rather than presenting the product features or services themselves.', '', 'https://abacklaunch.com/?utm_source=freeai.run', 'https://abacklaunch.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
