  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('70ba5510-364c-4fee-9c3f-53afc2293d01', 'webnovel-ai', 'Webnovel AI', 'WebNovel AI is an AI-driven planning tool specifically designed for web serial novel creators. It helps users transform initial ideas into complete story outlines and chapter drafts, covering the entire process from story conception, worldbuilding, and character design to chapter writing. Unlike general-purpose writing AI, WebNovel AI is optimized for platforms like Royal Road and Scribble Hub, offering structured workflows and genre templates that allow creators to quickly generate serial content aligned with platform styles.', '', 'https://webnovelai.io/?utm_source=freeai.run', 'https://webnovelai.io/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
