  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('b5b662be-acbd-4918-9f04-fe0752beee89', 'collage87', 'Collage87', 'Collage87 is an online photo collage and photo grid generator focused on quickly arranging multiple images into regular or custom layouts with zero learning curve. It runs in the browser, requires no account, supports high‑resolution exports with no watermark, and fits creators who prefer a streamlined workflow. Compared to general image editors, it concentrates on the “collage/grid” scenario and provides instant preview plus basic layout controls (spacing, margins, corner radius, canvas size). It’s ideal for lightweight, consistent output needs such as social posts, draft posters, and album page layouts.', '', 'https://collage87.com/?utm_source=freeai.run', 'https://collage87.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
