  SELECT id INTO cat_id FROM categories WHERE slug = 'hinh-anh';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('5a116c95-0008-4c10-8b4d-fc374e67663e', 'kling-ai-video-generator', 'Kling AI Video Generator', 'Kling AI Video is a type of AI video tool designed for content generation, primarily used to automatically convert text descriptions or static images into short video clips. It addresses the problem of “how to quickly obtain usable video content without filming materials or production capabilities,” making it suitable for lightweight creation and concept expression. Unlike traditional video editing software, this type of tool does not rely on manual editing but directly generates visuals through generative models. Compared to text-to-image tools, it adds motion and a time dimension, but still has certain limitations in controllability and duration, making it more suitable for generating short clips rather than complete videos.', '', 'https://www.klingaivideo.com/?utm_source=freeai.run', 'https://www.klingaivideo.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
