  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('aff3fafd-4af2-4b76-8ce1-08c27fac4c69', 'gemini-pro', 'Gemini Pro', 'GeminiPro.org is an online tool website providing generative AI chat and text generation capabilities, mainly aimed at scenarios where large models can be used directly without configuration. Users can enter questions, instructions, or text on the webpage to get answers, generate content, or receive simple code assistance. Compared with official model platforms, these types of sites emphasize "ready-to-use" access, lowering the entry barrier, but usually have limited functionality, stability, and data transparency. Overall, it is positioned more as a lightweight AI entry point, suitable for temporary queries, content draft generation, and other basic needs, rather than a production tool for long-term reliance.', '', 'https://www.geminipro.org/?utm_source=freeai.run', 'https://www.geminipro.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
