  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('baa572f8-7d2a-428b-8cfb-417da38d4ae3', 'skyreels-v4', 'Skyreels V4', 'SkyReels‑V4.ai is a multimodal AI-powered video and audio generation platform. Users can quickly create short video content with synchronized audio using text, images, audio, or mask inputs. Its core feature is the ability to output complete audio-video content in a single step, without separate recording or post-dubbing. Unlike most AI tools that only support silent video generation, SkyReels‑V4 also offers video restoration and local editing capabilities, making it ideal for quickly producing short films, narrative segments, or prototype visual content.', '', 'https://skyreels-v4.ai/?utm_source=freeai.run', 'https://skyreels-v4.ai/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
