  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('06af5b0f-1303-4cd1-87eb-c3088f2ca894', 'nano-banana-3', 'nano banana 3', 'Nano Banana 3 & Pro is a browser-based AI image generation and lightweight editing tool for producing high-resolution visuals from text prompts and reference images. It combines common tasks—multi-image blending, style transfer, background replacement, and in-image text edits—into a single workflow, and uses credits-based plans to set usage limits and caps. It’s best for rapid iteration and asset output, not for replacing a professional, fine-grained photo editor.', '', 'https://www.nano-banana-3.org/?utm_source=freeai.run', 'https://www.nano-banana-3.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
