  VALUES ('f3565fd0-c135-4445-8a13-3fdf5e46f718', 'open-launch', 'Open-Launch', 'Open Launch 是一个面向技术产品与独立开发者的发现与发布平台，被广泛视为 Product Hunt 的开源替代方案之一。它的核心目标是为开发者、创业团队以及技术爱好者提供一个更加公平、透明且低门槛的产品曝光渠道，让更多优秀但资源有限的项目也能获得关注与成长机会。', '', 'https://open-launch.com/projects/free-ai-tools?utm_source=freeai.run', 'https://open-launch.com/projects/free-ai-tools?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
