  VALUES ('c67a2e61-b230-491e-956f-281fa0eb48eb', 'nano-banana-2', 'Nano Banana 2', 'Nano Banana (nano-banana.love) is an online platform for AI image generation and editing. Its core approach is task-first: users pick a desired outcome before generating, instead of starting from a blank prompt. The site provides entry points for headshot enhancement, product-image workflows, stylized portraits, and practical image-editing tools, along with style pages, examples, and pricing details. This makes it easier to test quality for free first, then upgrade based on needed resolution, queue speed, and output volume.', '', 'https://nano-banana.love/?utm_source=freeai.run', 'https://nano-banana.love/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
