  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('3d99cac3-fafa-4c8e-a7c3-7d9f5f53d7f4', 'grok-video-generator', 'Grok Video Generator', 'GrokVideo.pro is anAI video generation toolwhose core capability is turning text prompts or static images directly into short video content. It does not offer traditional timeline editing or complex post-production. Instead, it relies on pre-trained models to automatically handle motion, style changes, and basic animation effects.From a product positioning perspective, it is closer to an “automated video generator” rather than a video editing application for professional creators. The tool primarily addresses the need ofusers with no editing experience who want to quickly obtain usable video assets, such as for social platforms, presentations, or simple promotional content.Compared to AI video tools that emphasize fine-grained control, GrokVideo.pro follows an “input → generate” workflow. It is well suited for scenarios where speed and low learning cost matter more than precise camera or shot control.', '', 'https://grokvideo.pro/?utm_source=freeai.run', 'https://grokvideo.pro/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
