  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('a8302aa9-42c0-4f7d-9c06-e545b46b4389', 'upscayl', 'upscayl', 'Upscayl is a tool focused onAI-powered image super-resolution and enhancement, capable of enlarging low-resolution or blurry images while preserving as much detail as possible. It is ideal for scenarios that require improving visual quality. At its core, it uses open-source deep learning models (such as Real‑ESRGAN) to “intelligently fill in” missing pixel information after upscaling, rather than simply stretching pixels. Upscayl offerscross-platform desktop versions (Windows, macOS, Linux) and an optional cloud browser version, allowing users to choose between local processing or online use, which provides flexibility compared to similar tools. The tool suits users concerned with privacy or cost, but may be less suitable for those relying solely on low-performance hardware or seeking fast cloud-based processing.', '', 'https://www.upscayl.app/?utm_source=freeai.run', 'https://www.upscayl.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
