  SELECT id INTO cat_id FROM categories WHERE slug = 'kinh-doanh';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('b46a17fa-dcc2-424b-bfd9-798023388f2f', 'needle', 'Needle', 'Needle is a tool centered around “AI-powered search + information organization,” designed to extract, consolidate, and output structured results from multiple information sources. Rather than simply returning links, it aims to provide summaries, key points, or direct answers, reducing the need for users to read and filter content one by one. Compared to traditional search engines, it emphasizes result organization; compared to general conversational AI, it relies more on retrieval-based responses, making its information sources more traceable. It is particularly suitable for research, content analysis, and understanding complex topics.', '', 'https://useneedle.net/?utm_source=freeai.run', 'https://useneedle.net/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
  ON CONFLICT (slug) DO NOTHING;

  SELECT id INTO cat_id FROM categories WHERE slug = 'hinh-anh';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('2e29c59a-a407-4840-9e29-e9725124ae27', 'gemini-ai-photo-editor', 'Gemini AI Photo Editor', 'Gemini AI Photo Editor is a browser-based AI image editing tool focused on fast, intelligent enhancement of existing photos. Users can upload images and describe their editing needs in natural language to perform background replacement, color optimization, watermark removal, and style transformation. Compared to traditional desktop editing software, it requires no complex operations or design skills, making it ideal for scenarios that need quick, high-quality visual content. The tool is not suitable for multi-layer professional retouching or complex compositing and is primarily intended for single-image enhancement and artistic processing.', '', 'https://www.geminiaiphotoeditor.app/?utm_source=freeai.run', 'https://www.geminiaiphotoeditor.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
