  VALUES ('cd24fc16-b166-43cf-a4c1-f10434fdff3f', 'indieai-directory', 'IndieAI Directory', 'IndieAI Directory 是一个专门收录独立开发者 AI 工具与 AI SaaS 产品的导航目录网站，主要用于帮助用户发现和浏览由个人或小团队开发的 AI 应用。平台通过分类列表的方式整理不同类型的 AI 工具，例如内容生成、图像生成、自动化工具和开发者工具，让用户能够在一个页面中快速查看并跳转到对应产品的网站。与一些大型 AI 工具目录不同，这类目录更偏向展示新上线或小众的 AI 项目，因此用户常常可以在这里发现尚未被广泛收录的 AI 产品。对于想了解 AI 产品生态、寻找新工具或观察独立开发者项目趋势的人来说，这类网站通常作为一个工具发现入口使用，而不是直接提供 AI 功能的平台。', '', 'https://indieai.directory/?utm_source=freeai.run', 'https://indieai.directory/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
