  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('56985b6c-5545-4320-a437-deba28575ad1', 'shipgrowth', 'ShipGrowth', 'ShipGrowth.dev is a third-party directory platform for the AI tool ecosystem, designed to centrally collect, search, and showcase various AI applications. It addresses the problem of scattered tool information and difficulty in quick comparison, allowing users to find basic information and pricing of different AI products in one place. Unlike pure search engines or technical review sites, ShipGrowth emphasizes "tool discovery + directory listing + developer exposure," making it suitable for scenarios where users want to quickly understand market tools or increase their product visibility.', '', 'https://shipgrowth.dev/?utm_source=freeai.run', 'https://shipgrowth.dev/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
