  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('783e4a98-c5d5-4457-a116-d19ee25d0aa3', 'seedance-40', 'seedance 4.0', 'Seedance4.video is an AI-powered video generation platform that automatically creates complete videos from text prompts or reference materials. It belongs to the category of AI video creation tools, aiming to enable users to quickly produce high-quality video content without professional editing skills. Compared to traditional editing software or some text-to-video tools, Seedance4.video focuses more on video coherence and stylistic consistency, suitable for social shorts, product promotions, and educational tutorials. The platform uses a credit point system to control generation times, allowing users to flexibly choose a plan based on their needs.', '', 'https://www.seedance4.video/?utm_source=freeai.run', 'https://www.seedance4.video/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
