  VALUES ('7426d197-08d6-4610-912c-2ad30ab04054', 'agentworktools', 'AgentWork.Tools', 'AgentWork.Tools (agentwork.tools) is a directory for discovering AI tools and SaaS products, serving both tool seekers and tool creators. It groups listings by category, supports search/filtering and submissions, and offers visibility options such as Free Listing and Featured Listing. It behaves more like a listing platform than an editorial review site: great for shortlisting and getting listed, not for “authoritative rankings.”', '', 'https://agentwork.tools/?utm_source=freeai.run', 'https://agentwork.tools/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
