  VALUES ('84fa81d9-d5f9-4540-bda0-f97eedf4ad2b', 'thumbnew', 'ThumbNew', 'ThumbNew is an online AI thumbnail generator built for YouTube creators. It’s designed for people who want usable thumbnails quickly without relying on heavyweight design software. You enter a short text prompt and get multiple visual options, with an emphasis on readability, contrast, and layout that works at small preview sizes. Overall, it favors rapid iteration over pixel-perfect, deep design workflows.', '', 'https://thumbnew.netlify.app/?utm_source=freeai.run', 'https://thumbnew.netlify.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
