  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('cfddb9f5-5048-4f27-9073-3e57f1c61dde', 'directory-for-ai', 'Directory For AI', 'DirectoryForAI is a navigation-style website for collecting and organizing AI tools. Its core purpose is to help users browse different types of AI products on a single page and quickly jump to their official websites. By organizing tools through categories and tags, it addresses the problem of “scattered tools and difficult filtering.” Unlike review platforms, it does not provide in-depth comparisons or rating systems, focusing instead on tool indexing and discovery. It is suitable for early-stage research or when you don’t yet have a clear target, helping you quickly build a shortlist of candidate tools.', '', 'https://directoryforai.com/?utm_source=freeai.run', 'https://directoryforai.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
