  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('289a61d2-c35b-4d5d-8c0e-e9134e316d2c', 'launch', 'Launch', 'LaunchSoar is a third-party tool directory for creators, product managers, and tool explorers, primarily organizing various online tools and AI products. It categorizes tools by function (e.g., video production, writing assistance, productivity tools) for easy browsing and filtering. The website itself does not provide tool functionality; instead, it helps users compare different tools and determine which best fit their use cases through directories and tags, reducing the time cost of searching and evaluating tools. Compared to standard search engines, it focuses more on visual presentation and category organization, allowing users to quickly get an overview and core information of tools.', '', 'https://launchsoar.com/?utm_source=freeai.run', 'https://launchsoar.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
