  VALUES ('eac553fb-eb8c-4002-8d3e-c6f0f4f1b833', 'alnewtool-rising-al-tool-directory-8667', 'AlNewTool - Rising Al Tool Directory', 'AINewTool is a website directory designed to collect and organize AI tools, helping users discover new AI products across different fields. The site presents various AI applications through categorized listings, such as content generation, design tools, development assistants, and productivity tools. Users can browse categories, read brief introductions, and directly navigate to the official websites of the listed tools.', '', 'https://ainewtool.site/?utm_source=freeai.run', 'https://ainewtool.site/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
