  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('444d873e-5cdb-456f-bb87-15f091f270e1', 'gpt-img', 'GPT-IMG', 'GPT‑IMG is an online tool focused on AI image and short video generation. Users can quickly create visual content using text prompts or by uploading images. Its core purpose is to transform text or materials into usable images and short videos without the need for traditional design software skills. Unlike platforms that only support single-image generation, GPT‑IMG covers both static images and short video creation, making it suitable for content creators, social media managers, and small businesses when producing visual assets. It also offers multiple model options to meet different style requirements. The platform uses a pay-per-use or subscription model to manage usage, ideal for on-demand visual content generation but not intended for full professional design workflows or large-scale animation production.', '', 'https://gpt-img.com/?utm_source=freeai.run', 'https://gpt-img.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
