  VALUES ('9bde3013-26a6-44bb-ac26-478501d9f0bb', 'aback-tools', 'Aback Tools', 'Aback Tools (abacktools.com) is a browser-based catalog of small utilities; under/toolsyou’ll find image conversion, data/document conversion, code and configuration processing, plus diagnostic pages for sites, HTTP, email, and DNS. The homepage claims free access, no installation, and no signup required—treat each tool page as the source of truth if the flow differs. Typical needs are one-off format checks or snippet-level text work without installing a desktop client. Compared with single-purpose converter sites, it leans on breadth and task-specific pages; whether precision, compliance, and privacy fit your case still depends on each tool’s own description.', '', 'https://abacktools.com/?utm_source=freeai.run', 'https://abacktools.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'free', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
  ON CONFLICT (slug) DO NOTHING;

