  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('8f323ade-d289-40d7-9b55-2fe797406e00', 'video-to-text', 'Video to Text', 'Video to Text is a browser-based service foralready recordedvideo and audio: upload a file, get timestamped segments, optional speaker labels and multilingual recognition, and export TXT/SRT/VTT/CSV. It turns speech into text you can search, caption, or move into spreadsheets—tighter than digging for “extra” transcription inside an editor or meeting stack. You buy minutes up front; new accounts get a stated free allowance, and per-file size and duration caps appear in the FAQ. It fits teams that want standard exports and accept cloud processing; offline-only stacks or bans on third-party hosting of originals are a mismatch.', '', 'https://video2text.net/?utm_source=freeai.run', 'https://video2text.net/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
