  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('ec028999-3431-4952-b824-bbb858da1d12', 'flow-ai-video', 'flow ai video', 'Flow AI Video is an online AI video generation tool designed to automatically convert text descriptions or image assets into short video content. Users do not need filming or editing experience—simply enter prompts or upload images to generate video clips with dynamic effects. The core positioning of this tool is “rapid content generation” rather than fine-grained editing, making it suitable for creative validation or lightweight video production. Compared to traditional editing software, it reduces time costs, but still has limitations in detailed control and complex storytelling. It is better suited for short-form content and early-stage creation.', '', 'https://www.flowaivideo.org/?utm_source=freeai.run', 'https://www.flowaivideo.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
