  SELECT id INTO cat_id FROM categories WHERE slug = 'video';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('ef4dc5fe-ebbb-468b-84c3-b793cb24135d', 'deepseek-video', 'deepseek video', 'DeepSeek Video is an AI-powered video generation tool that can quickly convert text descriptions or static images into dynamic video content. Its core functionality allows users to create short videos, social media content, or educational presentations without professional editing experience. Compared to traditional video editing software, it emphasizes automated workflows, requiring almost no manual adjustments from concept to finished video. However, for projects that require precise editing, highly customized effects, or professional film production, its capabilities are limited. The platform is suitable for quickly generating usable video clips, testing ideas, or producing small promotional content.', '', 'https://www.deepseek-video.org/?utm_source=freeai.run', 'https://www.deepseek-video.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
