  VALUES ('ceccf7c4-69df-4214-b19e-d03bcd813a98', 'flyploy', 'Flyploy', 'FlyPloy Partners is a partner showcase page provided by the FlyPloy platform, designed to centrally display websites, tools, or developer resources related to its ecosystem. FlyPloy itself is a deployment platform for developers and creators, while this page acts as an “ecosystem directory” that helps users discover partner projects related to deployment, development, or online tools.', '', 'https://flyploy.com/en/partners?utm_source=freeai.run', 'https://flyploy.com/en/partners?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
