  SELECT id INTO cat_id FROM categories WHERE slug = 'hinh-anh';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('4dc69fd3-cf6e-4bfb-b624-b723edaa95a6', 'z-image-2', 'z image 2', 'Z-Image-2.0 (zimage2.org) is an AI image generation and editing website designed to run in the browser. It brings text-to-image creation, reference-based generation, style transfer, background editing, and in-image text changes into one online workflow, so it feels more like a lightweight image workspace for creators and marketing teams than a single-purpose retouching utility. If your goal is to produce high-resolution visual drafts, product images, or social media assets quickly, this kind of site is convenient; if you need an auditable local workflow or tightly controlled data handling, you should review its terms and usage boundaries more carefully.', '', 'https://www.zimage2.org/?utm_source=freeai.run', 'https://www.zimage2.org/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
