  SELECT id INTO cat_id FROM categories WHERE slug = 'hinh-anh';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('12826f5c-ea99-4fe8-b56d-9265ec0fd515', 'ai-image-agent-9089', 'ai image agent', 'AI Image Agent (aiimageagent.app) is an online AI image generator aimed at creators. Its main workflow combines text-to-image generation, image-to-image editing, model switching, and high-resolution export in a single web interface. It works more like a lightweight image production workspace for quick concepting, revision, and social or content asset export than a professional design suite built around complex layer editing. If you want to turn prompts or reference images into usable visuals directly in the browser, this kind of tool is easy to pick up; if you care more about local workflows, stricter compliance controls, or heavier collaboration pipelines, you should verify the terms, quotas, and permission boundaries first.', '', 'https://www.aiimageagent.app/?utm_source=freeai.run', 'https://www.aiimageagent.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
  ON CONFLICT (slug) DO NOTHING;

  SELECT id INTO cat_id FROM categories WHERE slug = 'hinh-anh';
  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('49118e3c-f6a9-41b0-9434-ef4239cc1032', 'ai-image-agent', 'AI-Image-Agent', 'AI‑Image‑Agent is a browser-basedAI image generation and style transfer tool. Its core function is to quickly convert user-provided text prompts into visual images, while also supporting style transformation or effect adjustments on existing images. This tool addresses the challenge ofcreating original visual content without design experience, making it suitable for creators and teams who need to quickly produce illustrations, concept art, or marketing assets. Compared to similar platforms, it offers greater flexibility inmulti-model selection, batch processing, and high-resolution output, but is not intended for complex UI design, animation production, or high-precision industrial rendering.', '', 'https://www.ai-image-agent.com/?utm_source=freeai.run', 'https://www.ai-image-agent.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
