  INSERT INTO tools (id, slug, name, description_en, description_vi, website_url, affiliate_url, thumbnail_url, pricing, tags, category_id, featured, status, source, click_count)
  VALUES ('70d523a8-7f62-44cf-9999-dcddb6408906', 'seedream-50', 'Seedream 5.0', 'Seedream 5.0 (at seedream5ai.app) is a browser-basedAI image generation and editing toolpowered by ByteDance''s Seedream series AI models. It is designed to convert natural language descriptions or uploaded images into high-quality visual creations. The platform supports not only text-to-image generation but also text-guided image editing, image blending, and style transfer, allowing users to produce print-quality visuals without any design experience. Compared to lightweight tools, Seedream 5.0 emphasizes native4K resolution outputand batch image consistency management, making it suitable for creators, marketing content producers, or e-commerce visual teams who require detailed artistic control.', '', 'https://www.seedream5ai.app/?utm_source=freeai.run', 'https://www.seedream5ai.app/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
