  VALUES ('ada9febb-fc1c-48b0-aaae-64c3ed9c66e1', 'banana-ai', 'banana ai', 'Banana AIis an online platform that integrates AI-powered image generation and editing. Users can create new images, edit existing photos, change backgrounds, and apply style transformations through natural language prompts (e.g., writing instructions in text) or by uploading images. Unlike traditional manual editing tools, no knowledge of masks or layers is required, as the AI interprets intentions and automates the processing. It also allows switching between multiple AI models within the same interface. This flexibility enables content creators and designers to work in a prompt-driven workflow for visual production.', '', 'https://banana-ai.art/?utm_source=freeai.run', 'https://banana-ai.art/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
