  VALUES ('66213e75-6617-42d6-8499-a21b19bf08e6', 'hailuo-video', 'hailuo video', 'Hailuo‑3 is a browser-based AI video generation tool that quickly creates short videos from text descriptions or image assets. It addresses the complexity of traditional video production and the high editing threshold, allowing users to produce visual content without professional editing skills. Compared with similar AI video tools, Hailuo‑3 focuses on rapid generation and multi-aspect ratio output, suitable for social short videos, educational demos, or product showcases, while it is not ideal for long-form films or detailed visual effects production.', '', 'https://www.hailuo-3.com/?utm_source=freeai.run', 'https://www.hailuo-3.com/?utm_source=freeai.run', 'https://www.freeai.run/og.png', 'freemium', '[]'::jsonb, cat_id, false, 'published', 'freeai.run', 0)
